def _path_to_module(
    file_path: str,
) -> str:
    path = PurePosixPath(file_path)

    if path.name == "__init__.py":
        module_parts = path.parent.parts
    else:
        module_parts = path.with_suffix("").parts

    return ".".join(module_parts)

